    #[test]
    fn convert_source_populates_mirror_as_none() {
        // Slice 3 wires `convert_source` to set `mirror: None` for
        // registry / git resolved sources. Pinning that no real mirror
        // URL is invented before the proxy fetch surface ships.
        let registry = ResolvedSource::Registry {
            url: "https://crates.io".to_string(),
            dir: PathBuf::from("/cache/http"),
        };
        let lock_src = convert_source(&registry, Path::new("/proj"));
        match lock_src {
            LockSource::Registry { url, mirror } => {
                assert_eq!(url, "https://crates.io");
                assert_eq!(mirror, None);
            }
            other => panic!("expected Registry, got {other:?}"),
        }

        let git = ResolvedSource::Git {
            url: "https://github.com/foo/bar".to_string(),
            reference: Some(GitRef::Tag("v1.0".to_string())),
            dir: PathBuf::from("/cache/git/bar"),
            resolved_rev: "abcd1234".to_string(),
        };
        let lock_src = convert_source(&git, Path::new("/proj"));
        match lock_src {
            LockSource::Git {
                url,
                reference,
                resolved_rev,
                mirror,
            } => {
                assert_eq!(url, "https://github.com/foo/bar");
                assert_eq!(reference, Some(GitRef::Tag("v1.0".to_string())),);
                // convert_source persists the resolved commit as the pin.
                assert_eq!(resolved_rev.as_deref(), Some("abcd1234"));
                assert_eq!(mirror, None);
            }
            other => panic!("expected Git, got {other:?}"),
        }
    }

    #[test]
    fn deterministic_output_across_writes() {
        let lockfile = Lockfile {
            version: 1,
            packages: vec![
                LockedPackage {
                    name: "z-last".to_string(),
                    version: "1.0.0".to_string(),
                    source: LockSource::Root,
                    content_hash: "blake3:z".to_string(),
                    dependencies: vec![],
                },
                LockedPackage {
                    name: "a-first".to_string(),
                    version: "1.0.0".to_string(),
                    source: LockSource::Path(PathBuf::from("a")),
                    content_hash: "blake3:a".to_string(),
                    dependencies: vec![],
                },
            ],
        };
        let out1 = lockfile.to_toml();
        let out2 = lockfile.to_toml();
        assert_eq!(out1, out2);
        // a-first sorts before z-last
        let a_idx = out1.find("a-first").expect("a-first present");
        let z_idx = out1.find("z-last").expect("z-last present");
        assert!(a_idx < z_idx);
    }

