        let h = compute_content_hash(b"abc");
        assert!(h.starts_with("blake3:"));
        let hex = &h["blake3:".len()..];
        // BLAKE3 default output is 32 bytes → 64 hex chars
        assert_eq!(hex.len(), 64);
        assert!(hex
            .chars()
            .all(|c| c.is_ascii_hexdigit() && !c.is_ascii_uppercase()));
